function firstDayBeenInAllRooms(nextVisit) {
    let n = nextVisit.length;
    let ans = 0, MOD = BigInt(1e9 + 7);
    let dp = new Array(n).fill(BigInt(0));

    for (let i = 1; i < n; ++i) {
        dp[i] = (dp[i - 1] * BigInt(2) - dp[nextVisit[i - 1]] + BigInt(2)) % MOD;
    }

    return parseInt(dp[n - 1]);
}
